server/tests/test_validate.py :: test_validate_rejects_empty_bytes
def test_validate_rejects_empty_bytes() -> None:
    try:
        validate_image(b"", "empty.png")
    except ValueError:
        return
    raise AssertionError("Expected ValueError")

server/tests/test_validate.py :: test_validate_uploaded_image_empty_raises
def test_validate_uploaded_image_empty_raises() -> None:
    try:
        validate_uploaded_image(b"", "empty.png")
    except ConversionError as error:
        assert error.status_code == 400
        return
    raise AssertionError("Expected ConversionError")
